+bool SimplifyCFGOpt::simplifyCmpIntrinsicSwitch(SwitchInst *SI,
+                                               IRBuilder<> &Builder) {
+  Value *Cond = SI->getCondition();
+  BasicBlock *BB = SI->getParent();
+  auto *II = dyn_cast<IntrinsicInst>(Cond);
+  if (!II)
+    return false;
+  Intrinsic::ID ID = II->getIntrinsicID();
+  if (ID != Intrinsic::ucmp && ID != Intrinsic::scmp)
+    return false;
+
+  Value *A = II->getArgOperand(0);
+  Value *B = II->getArgOperand(1);
+  Type *OpType = A->getType();
+  // Only handle integer comparisons.
+  if (!OpType->isIntegerTy())
+    return false;
+
+  // Determine mapping from result values to successor blocks.
+  // Determine mapping from result values to successor blocks.
+  SmallVector<BasicBlock *, 3> DestForVal(3, nullptr);
+  // Default destination.
+  BasicBlock *DefaultDest = SI->getDefaultDest();
+  // Iterate over cases.
+  for (auto &Case : SI->cases()) {
+    ConstantInt *CaseVal = Case.getCaseValue();
+    // We only care about i8 constants, but ucmp returns i8 (or maybe i2?).
+    // Convert to signed 8-bit value.
+    int8_t Val = CaseVal->getValue().getSExtValue();
+    // Map -1,0,1 to indices 0,1,2.
+    if (Val >= -1 && Val <= 1)
+      DestForVal[Val + 1] = Case.getCaseSuccessor();
+  }
+
+  // Determine destinations for -1, 0, 1.
+  auto getDest = [&](int8_t Val) -> BasicBlock* {
+    BasicBlock *Dest = DestForVal[Val + 1];
+    if (Dest)
+      return Dest;
+    return DefaultDest;
+  };
+  BasicBlock *DestM1 = getDest(-1);
+  BasicBlock *Dest0 = getDest(0);
+  BasicBlock *Dest1 = getDest(1);
+
+  // All three destinations must be either DestM1 or Dest0 or Dest1.
+  // We need exactly two distinct destinations.
+  SmallSet<BasicBlock *, 2> Dests;
+  Dests.insert(DestM1);
+  Dests.insert(Dest0);
+  Dests.insert(Dest1);
+  if (Dests.size() != 2)
+    return false;
+
+  // Determine which destination corresponds to which predicate.
+  // We'll create an icmp with appropriate predicate and branch to DestTrue
+  // when condition holds, otherwise DestFalse.
+  BasicBlock *DestTrue = nullptr;
+  BasicBlock *DestFalse = nullptr;
+  ICmpInst::Predicate Pred;
+  // Check possible patterns.
+  // Check possible patterns.
+  if (DestM1 == Dest0 && Dest0 != Dest1) {
+    // -1 and 0 go to same destination, 1 goes to other.
+    // This means a > b (unsigned for ucmp, signed for scmp).
+    Pred = ID == Intrinsic::ucmp ? ICmpInst::ICMP_UGT : ICmpInst::ICMP_SGT;
+    DestTrue = Dest1;
+    DestFalse = DestM1;
+  } else if (DestM1 != Dest0 && Dest0 == Dest1) {
+    // -1 goes to one destination, 0 and 1 go to other.
+    // This means a < b.
+    Pred = ID == Intrinsic::ucmp ? ICmpInst::ICMP_ULT : ICmpInst::ICMP_SLT;
+    DestTrue = DestM1;
+    DestFalse = Dest0;
+  } else if (DestM1 == Dest1 && Dest0 != Dest1) {
+    // -1 and 1 go to same destination, 0 goes to other.
+    // This means a == b.
+    Pred = ICmpInst::ICMP_EQ;
+    DestTrue = Dest0;
+    DestFalse = DestM1;
+  } else if (DestM1 != Dest0 && Dest0 != Dest1 && DestM1 == Dest1) {
+    // Actually same as above.
+    Pred = ICmpInst::ICMP_EQ;
+    DestTrue = Dest0;
+    DestFalse = DestM1;
+  } else {
+    // Other patterns not handled (e.g., all same destination).
+    return false;
+  }
+
+  // Create icmp and branch.
+  // Create icmp and branch.
+  Value *Cmp = Builder.CreateICmp(Pred, A, B, "cmp");
+  BranchInst *NewBI = Builder.CreateCondBr(Cmp, DestTrue, DestFalse);
+
+  // Update PHI nodes in successors.
+  auto UpdatePHI = [&](BasicBlock *Dest, unsigned NumEdges) {
+    if (NumEdges <= 1) return;
+    for (PHINode &PN : Dest->phis()) {
+      // Remove extra incoming values from BB.
+      for (unsigned I = 0, E = NumEdges - 1; I != E; ++I)
+        PN.removeIncomingValue(BB);
+    }
+  };
+
+  // Compute number of edges from BB to each destination.
+  auto CountEdges = [&](BasicBlock *Dest) {
+    unsigned Count = 0;
+    if (Dest == SI->getDefaultDest())
+      ++Count;
+    for (auto &Case : SI->cases())
+      if (Case.getCaseSuccessor() == Dest)
+        ++Count;
+    return Count;
+  };
+
+  UpdatePHI(DestTrue, CountEdges(DestTrue));
+  UpdatePHI(DestFalse, CountEdges(DestFalse));
+
+  // Remove the switch.
+  SI->eraseFromParent();
+  // The intrinsic may now be dead.
+  if (II->use_empty())
+    RecursivelyDeleteTriviallyDeadInstructions(II);
+  return true;
+}

 // Replaces
 //   (indirectbr (select cond, blockaddress(@fn, BlockA),
@@ -7152,7 +7279,9 @@ bool SimplifyCFGOpt::simplifySwitch(SwitchInst *SI, IRBuilder<> &Builder) {
       if (foldValueComparisonIntoPredecessors(SI, Builder))
         return requestResimplify();
   }
-
+  // Try to simplify switch on llvm.{u,s}cmp intrinsic.
+  if (simplifyCmpIntrinsicSwitch(SI, Builder))
+    return requestResimplify();
   // Try to transform the switch into an icmp and a branch.
   // The conversion from switch to comparison may lose information on
   // impossible switch values, so disable it early in the pipeline.
